/**
 * SVG-аватары пилотной группы (10 спортивных персонажей).
 * Сначала читаем файл с диска; если нет — встроенная копия в коде.
 */

function legion_pilot_avatar_svg_content($index) {
    $index = max(1, min(10, (int) $index));
    $embedded = legion_pilot_avatar_svgs_embedded();
    return isset($embedded[$index]) ? $embedded[$index] : $embedded[1];
}

